import{_ as a,o as s,c as i,a2 as r}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Colas, back pressure y errores","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/05-colas-back-pressure-y-errores.md","filePath":"data-engineering/nifi/05-colas-back-pressure-y-errores.md","lastUpdated":1782521464000}'),n={name:"data-engineering/nifi/05-colas-back-pressure-y-errores.md"};function o(t,e,l,p,c,d){return s(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="colas-back-pressure-y-errores" tabindex="-1">Colas, back pressure y errores <a class="header-anchor" href="#colas-back-pressure-y-errores" aria-label="Permalink to &quot;Colas, back pressure y errores&quot;">​</a></h1><p>Las colas son una de las partes mas importantes de NiFi. Permiten desacoplar fases, absorber picos y ver donde se atasca el flujo.</p><h2 id="connections-como-colas" tabindex="-1">Connections como colas <a class="header-anchor" href="#connections-como-colas" aria-label="Permalink to &quot;Connections como colas&quot;">​</a></h2><p>Cada connection almacena FlowFiles entre componentes.</p><p>En una connection puedes revisar:</p><ul><li>Numero de FlowFiles.</li><li>Tamano acumulado.</li><li>FlowFiles en espera.</li><li>Edad de los datos.</li><li>Relaciones que alimentan la cola.</li><li>Priorizadores.</li></ul><p>Una cola creciente indica que la fase siguiente no consume al ritmo necesario.</p><h2 id="back-pressure" tabindex="-1">Back pressure <a class="header-anchor" href="#back-pressure" aria-label="Permalink to &quot;Back pressure&quot;">​</a></h2><p>Back pressure pausa el componente anterior cuando la cola alcanza un limite.</p><p>Limites comunes:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Object threshold: 10,000 FlowFiles</span></span>
<span class="line"><span>Data size threshold: 1 GB</span></span></code></pre></div><p>No existe un valor universal. Depende del tamano de los FlowFiles, disco disponible y criticidad del flujo.</p><h2 id="priorizadores" tabindex="-1">Priorizadores <a class="header-anchor" href="#priorizadores" aria-label="Permalink to &quot;Priorizadores&quot;">​</a></h2><p>Los prioritizers deciden que FlowFiles salen primero.</p><p>Ejemplos:</p><ul><li>First in, first out.</li><li>Prioridad por atributo.</li><li>Mas antiguo primero.</li><li>Mas reciente primero.</li></ul><p>Usalos cuando el orden importa o cuando quieres dar preferencia a eventos urgentes.</p><h2 id="penalization-y-yield" tabindex="-1">Penalization y yield <a class="header-anchor" href="#penalization-y-yield" aria-label="Permalink to &quot;Penalization y yield&quot;">​</a></h2><p>NiFi usa dos mecanismos importantes:</p><ul><li><strong>Penalization:</strong> retrasa un FlowFile concreto tras un problema.</li><li><strong>Yield:</strong> pausa temporalmente un processor cuando no puede avanzar.</li></ul><p>Esto evita bucles agresivos que consumen CPU sin progreso real.</p><h2 id="estrategias-de-error" tabindex="-1">Estrategias de error <a class="header-anchor" href="#estrategias-de-error" aria-label="Permalink to &quot;Estrategias de error&quot;">​</a></h2><p>Separa errores por tipo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>success -&gt; siguiente fase</span></span>
<span class="line"><span>retry -&gt; cola de reintentos</span></span>
<span class="line"><span>failure -&gt; cuarentena o dead letter</span></span></code></pre></div><p>No envies todos los fallos a la misma ruta si requieren acciones diferentes.</p><h2 id="retry-controlado" tabindex="-1">Retry controlado <a class="header-anchor" href="#retry-controlado" aria-label="Permalink to &quot;Retry controlado&quot;">​</a></h2><p>Un reintento debe tener limite.</p><p>Patron:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>failure temporal</span></span>
<span class="line"><span>  -&gt; UpdateAttribute retry_count + 1</span></span>
<span class="line"><span>  -&gt; RouteOnAttribute retry_count &lt; 3</span></span>
<span class="line"><span>      -&gt; esperar y reintentar</span></span>
<span class="line"><span>      -&gt; dead letter</span></span></code></pre></div><p>Si una API externa esta caida durante horas, reintentar sin control solo acumula ruido.</p><h2 id="dead-letter" tabindex="-1">Dead letter <a class="header-anchor" href="#dead-letter" aria-label="Permalink to &quot;Dead letter&quot;">​</a></h2><p>Una ruta dead letter conserva FlowFiles que no pueden procesarse.</p><p>Debe guardar:</p><ul><li>Contenido original.</li><li>Atributos relevantes.</li><li>Motivo del error.</li><li>Processor que fallo.</li><li>Fecha.</li><li>Numero de reintentos.</li></ul><p>La dead letter no es un vertedero invisible. Debe revisarse y tener retencion definida.</p><h2 id="cuarentena-de-datos" tabindex="-1">Cuarentena de datos <a class="header-anchor" href="#cuarentena-de-datos" aria-label="Permalink to &quot;Cuarentena de datos&quot;">​</a></h2><p>Para errores de calidad, usa una cuarentena separada.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ValidateRecord</span></span>
<span class="line"><span>  -&gt; valid -&gt; publish</span></span>
<span class="line"><span>  -&gt; invalid -&gt; quarantine/dataset=ventas/date=2026-06-25</span></span></code></pre></div><p>La cuarentena ayuda a corregir datos sin bloquear todo el pipeline, siempre que el negocio acepte publicar datos parciales.</p><h2 id="expiracion-de-flowfiles" tabindex="-1">Expiracion de FlowFiles <a class="header-anchor" href="#expiracion-de-flowfiles" aria-label="Permalink to &quot;Expiracion de FlowFiles&quot;">​</a></h2><p>Las connections pueden tener expiracion.</p><p>Usala con cuidado:</p><ul><li>Es util para datos que pierden valor con el tiempo.</li><li>Es peligrosa si no hay auditoria.</li><li>No debe ocultar errores recurrentes.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las colas tienen back pressure.</li><li>Hay rutas separadas para retry y fallo definitivo.</li><li>Los reintentos tienen limite.</li><li>Los errores conservan contexto.</li><li>La dead letter tiene propietario.</li><li>Las colas criticas tienen alertas.</li><li>No se auto-terminan failures sin justificacion.</li></ul>`,46)])])}const b=a(n,[["render",o]]);export{h as __pageData,b as default};
